import java.io.File;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;

public class SecurePathTraversal {

    public static void main(String[] args) throws IOException {
        String userInput = "../secretFile.txt";
        String directory = "/path/to/directory/";

        Path filePath = Paths.get(directory).resolve(Paths.get(userInput).normalize()).toAbsolutePath();

        if (!filePath.startsWith(Paths.get(directory))) {
            System.out.println("Access to files outside the directory is not allowed.");
            return;
        }

        File file = filePath.toFile();

        if (file.exists()) {
            byte[] fileContent = Files.readAllBytes(filePath);
            System.out.println(new String(fileContent));
        } else {
            System.out.println("File not found");
        }
    }
}

